import{_ as d,o as a,c as r,ai as e}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第十九课：读盘技巧","description":"","frontmatter":{},"headers":[],"relativePath":"guide/19-reading-charts.md","filePath":"guide/19-reading-charts.md","lastUpdated":0}'),h={name:"guide/19-reading-charts.md"};function l(o,t,i,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第十九课-读盘技巧" tabindex="-1">第十九课：读盘技巧 <a class="header-anchor" href="#第十九课-读盘技巧" aria-label="Permalink to “第十九课：读盘技巧”">​</a></h1><p>选好了股票，什么时候买？看盘是关键技能。</p><h2 id="一、盘面基础术语" tabindex="-1">一、盘面基础术语 <a class="header-anchor" href="#一、盘面基础术语" aria-label="Permalink to “一、盘面基础术语”">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>含义</th></tr></thead><tbody><tr><td>集合竞价</td><td>9:15-9:25，试探当天开盘方向</td></tr><tr><td>开盘价</td><td>9:30第一笔成交价</td></tr><tr><td>收盘价</td><td>15:00最后一笔成交价</td></tr><tr><td>涨停价</td><td>当日最高能涨到的价格</td></tr><tr><td>跌停价</td><td>当日最低能跌到的价格</td></tr><tr><td>振幅</td><td>最高价到最低价的差距</td></tr></tbody></table><h2 id="二、看盘要看什么" tabindex="-1">二、看盘要看什么？ <a class="header-anchor" href="#二、看盘要看什么" aria-label="Permalink to “二、看盘要看什么？”">​</a></h2><h3 id="_1-看大盘环境" tabindex="-1">1. 看大盘环境 <a class="header-anchor" href="#_1-看大盘环境" aria-label="Permalink to “1. 看大盘环境”">​</a></h3><p>不是所有时候都适合买股票：</p><table tabindex="0"><thead><tr><th>大盘环境</th><th>操作建议</th></tr></thead><tbody><tr><td>大盘上涨</td><td>积极一些</td></tr><tr><td>大盘震荡</td><td>控制仓位</td></tr><tr><td>大盘下跌</td><td>谨慎观望</td></tr></tbody></table><h3 id="_2-看板块联动" tabindex="-1">2. 看板块联动 <a class="header-anchor" href="#_2-看板块联动" aria-label="Permalink to “2. 看板块联动”">​</a></h3><p>个股要跟随板块走势：</p><ul><li>板块整体涨 → 个股更容易涨</li><li>板块整体跌 → 个股难以独善其身</li></ul><h3 id="_3-看分时走势" tabindex="-1">3. 看分时走势 <a class="header-anchor" href="#_3-看分时走势" aria-label="Permalink to “3. 看分时走势”">​</a></h3><table tabindex="0"><thead><tr><th>分时特征</th><th>信号</th></tr></thead><tbody><tr><td>白线在黄线上方</td><td>权重股在拉指数</td></tr><tr><td>白线在黄线下方</td><td>小盘股更活跃</td></tr><tr><td>股价全天横着走</td><td>主力控盘，不上不下</td></tr><tr><td>股价突然急拉</td><td>小心是诱多</td></tr></tbody></table><h2 id="三、尾盘操作技巧" tabindex="-1">三、尾盘操作技巧 <a class="header-anchor" href="#三、尾盘操作技巧" aria-label="Permalink to “三、尾盘操作技巧”">​</a></h2><p>尾盘（14:30-15:00）是<strong>最重要的操作时段</strong>：</p><table tabindex="0"><thead><tr><th>时间</th><th>适合做什么</th></tr></thead><tbody><tr><td>早盘（9:30-10:00）</td><td>观察为主，不急着买</td></tr><tr><td>中盘（10:00-14:00）</td><td>确认方向后操作</td></tr><tr><td>尾盘（14:30-15:00）</td><td>最佳买入/卖出时机</td></tr></tbody></table><blockquote><p>💡 <strong>老手多在尾盘买</strong>：经过一天的博弈，价格更真实。</p></blockquote><h2 id="四、盘口语言" tabindex="-1">四、盘口语言 <a class="header-anchor" href="#四、盘口语言" aria-label="Permalink to “四、盘口语言”">​</a></h2><h3 id="五档买卖盘" tabindex="-1">五档买卖盘 <a class="header-anchor" href="#五档买卖盘" aria-label="Permalink to “五档买卖盘”">​</a></h3><table tabindex="0"><thead><tr><th>位置</th><th>含义</th></tr></thead><tbody><tr><td>卖1-5</td><td>准备卖出的挂单</td></tr><tr><td>买1-5</td><td>准备买入的挂单</td></tr><tr><td>外盘（红）</td><td>主动买入的成交量</td></tr><tr><td>内盘（绿）</td><td>主动卖出的成交量</td></tr></tbody></table><p><strong>外盘 &gt; 内盘</strong>：买方更积极，股票偏强 <strong>内盘 &gt; 外盘</strong>：卖方更积极，股票偏弱</p><h3 id="大单解读" tabindex="-1">大单解读 <a class="header-anchor" href="#大单解读" aria-label="Permalink to “大单解读”">​</a></h3><table tabindex="0"><thead><tr><th>现象</th><th>含义</th></tr></thead><tbody><tr><td>大单买入</td><td>主力可能在吸筹</td></tr><tr><td>大单卖出</td><td>主力可能在出货</td></tr><tr><td>大单砸盘</td><td>可能有利空</td></tr></tbody></table><h2 id="五、集合竞价看盘" tabindex="-1">五、集合竞价看盘 <a class="header-anchor" href="#五、集合竞价看盘" aria-label="Permalink to “五、集合竞价看盘”">​</a></h2><p>每天9:15-9:25是观察主力意图的好时机：</p><ol><li><strong>看竞价涨幅</strong>：大幅高开（&gt;5%）要小心</li><li><strong>看成交量</strong>：量太大可能是诱多</li><li><strong>9:20后不能撤单</strong>：这时候的挂单更真实</li></ol><blockquote><p>🚨 <strong>9:15-9:20挂涨停买入的，可能是庄家钓鱼</strong>，别上当！</p></blockquote><h2 id="六、复盘的重要性" tabindex="-1">六、复盘的重要性 <a class="header-anchor" href="#六、复盘的重要性" aria-label="Permalink to “六、复盘的重要性”">​</a></h2><p>每天收盘后，花10分钟复盘：</p><table tabindex="0"><thead><tr><th>复盘内容</th><th>目的</th></tr></thead><tbody><tr><td>今天赚钱了吗</td><td>总结操作</td></tr><tr><td>明天怎么看</td><td>制定计划</td></tr><tr><td>持仓股有没有问题</td><td>决定去留</td></tr></tbody></table><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>今天你关注的某只股票，集合竞价时大幅高开7%，但9:20后成交量萎缩。你会追吗？为什么？</p></blockquote><hr><p><strong>下一课预告</strong>：最后一课，学习<strong>下单与成交</strong>——实操中的常见问题处理。</p>',34)])])}const g=d(h,[["render",l]]);export{p as __pageData,g as default};
